            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-10 增加入口温度规格占位",
          "target": {
            "type": "stream",
            "id": "feed-10"
